#!/usr/bin/env node
import { spawn } from "node:child_process";
import { setTimeout as wait } from "node:timers/promises";
import http from "node:http";

const CHROME = "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
const URL = "http://localhost:8080/index.html";
const RDP = 9344;

function getJSON(path, port) {
  return new Promise((resolve, reject) => {
    http.get({ host: "127.0.0.1", port, path }, (res) => {
      let buf = "";
      res.on("data", (c) => (buf += c));
      res.on("end", () => { try { resolve(JSON.parse(buf)); } catch { resolve(buf); } });
    }).on("error", reject);
  });
}

const chrome = spawn(CHROME, [
  "--headless=new",
  `--remote-debugging-port=${RDP}`,
  "--no-first-run",
  "--no-default-browser-check",
  "--disable-gpu",
  "--user-data-dir=/tmp/jb-coach-profile",
  URL,
], { stdio: ["ignore", "pipe", "pipe"] });
let chromeStderr = "";
chrome.stderr.on("data", (c) => (chromeStderr += c));

await wait(2500);
const tabs = await getJSON("/json", RDP);
const tab = Array.isArray(tabs) ? tabs.find((t) => t.url.includes("8080")) : null;
if (!tab) { console.error("[coach] no tab"); console.error(chromeStderr.slice(-1500)); chrome.kill(); process.exit(2); }

const ws = new WebSocket(tab.webSocketDebuggerUrl);
await new Promise((r) => ws.addEventListener("open", r, { once: true }));
let nextId = 0;
function call(method, params = {}) {
  return new Promise((resolve, reject) => {
    const id = ++nextId;
    function onMsg(ev) {
      const msg = JSON.parse(ev.data);
      if (msg.id !== id) return;
      ws.removeEventListener("message", onMsg);
      if (msg.error) reject(new Error(JSON.stringify(msg.error)));
      else resolve(msg.result);
    }
    ws.addEventListener("message", onMsg);
    ws.send(JSON.stringify({ id, method, params }));
  });
}
async function evalExpr(expression) {
  const res = await call("Runtime.evaluate", { expression, returnByValue: true, awaitPromise: true });
  if (res.exceptionDetails) throw new Error("eval threw: " + (res.exceptionDetails.exception?.description || res.exceptionDetails.text));
  return res.result.value;
}
await call("Page.enable");
await call("Runtime.enable");
await wait(3500);

await evalExpr("localStorage.removeItem('command_center_discovery_coach_done')");
const apiPresent = await evalExpr("typeof window.JobBoredDiscoveryCoach && typeof window.JobBoredDiscoveryCoach.start");
console.log("[coach] API present →", apiPresent);

await evalExpr("(typeof window.openDiscoveryDrawer === 'function' && window.openDiscoveryDrawer({ source:'coach-smoke' })) || true");
await wait(700);
const overlayCountFirstOpen = await evalExpr("document.querySelectorAll('.discovery-coachmark').length");
const overlayVisible = await evalExpr("(()=>{const el=document.querySelector('.discovery-coachmark'); if(!el) return false; return !el.hidden && getComputedStyle(el).display !== 'none';})()");
console.log("[coach] FIRST OPEN — overlay nodes:", overlayCountFirstOpen, "visible:", overlayVisible);

await evalExpr("(()=>{const c=window.JobBoredDiscoveryCoach; if(c) c.dismiss();})()");
await wait(300);
const flagAfterDismiss = await evalExpr("localStorage.getItem('command_center_discovery_coach_done')");
console.log("[coach] flag after dismiss:", flagAfterDismiss);

await evalExpr("(typeof window.closeDiscoveryDrawer === 'function' && window.closeDiscoveryDrawer()) || true");
await wait(200);
await evalExpr("(typeof window.openDiscoveryDrawer === 'function' && window.openDiscoveryDrawer({ source:'coach-smoke-2' })) || true");
await wait(700);
const overlayActiveSecondOpen = await evalExpr("(()=>{const c=window.JobBoredDiscoveryCoach; return c && typeof c._isActive==='function' ? c._isActive() : null;})()");
const overlayVisibleSecondOpen = await evalExpr("(()=>{const el=document.querySelector('.discovery-coachmark'); if(!el) return false; return !el.hidden && getComputedStyle(el).display !== 'none';})()");
console.log("[coach] SECOND OPEN — coach active:", overlayActiveSecondOpen, "overlay visible:", overlayVisibleSecondOpen);

ws.close(); chrome.kill(); process.exit(0);

